/**
 * Artifact system: types, generators, parsing.
 * Artifacts are saved markdown documents generated by agents.
 */

import type { ArtifactType } from './db'

export interface ArtifactTemplate {
  type: ArtifactType
  name: string
  description: string
  emoji: string
  defaultTitle: string
  // Prompt to feed the agent when generating this artifact
  prompt: string
  // Markdown skeleton for the artifact (used for the structure preview while streaming)
  skeleton: string
}

