export const ARTIFACT_LIST = Object.values(ARTIFACT_TEMPLATES)

/**
 * Parse a chat message to extract artifact blocks.
 * Format: <artifact type="TYPE" title="TITLE">\n...\n</artifact>
 */
export interface ParsedArtifact {
  type: ArtifactType
  title: string
  content: string
  startIndex: number
  endIndex: number
}

const ARTIFACT_RE = /<artifact\s+type="([a-z0-9_-]+)"(?:\s+title="([^"]*)")?\s*>([\s\S]*?)<\/artifact>/g

export function parseArtifacts(text: string): ParsedArtifact[] {
  const out: ParsedArtifact[] = []
  let m: RegExpExecArray | null
  ARTIFACT_RE.lastIndex = 0
  while ((m = ARTIFACT_RE.exec(text)) !== null) {
    const rawType = m[1]
    const title = m[2] || ARTIFACT_TEMPLATES[rawType as ArtifactType]?.defaultTitle || 'Artifact'
    const type = (ARTIFACT_TEMPLATES[rawType as ArtifactType] ? rawType : 'custom') as ArtifactType
    out.push({
      type,
      title,
      content: m[3].trim(),
      startIndex: m.index,
      endIndex: m.index + m[0].length,
    })
  }
  return out
}

/** Strip artifact blocks from a chat message for display. */
export function stripArtifacts(text: string): string {
  return text.replace(ARTIFACT_RE, '').replace(/\n{3,}/g, '\n\n').trim()
}

// ---------------------------------------------------------------------------
// HTML preview blocks
// ---------------------------------------------------------------------------
// Detects ```html ... ``` fenced code blocks in chat text. The model is
// instructed to wrap any HTML mockup / design in this exact format. We render
// it in a sandboxed iframe so the founder can see (and interact with) the
// visual the agent produced, right inside the conversation.

export interface ParsedHtmlBlock {
  /** Raw HTML to render in the iframe (srcdoc) */
  html: string
  /** Language tag after the fence — only "html" / "htm" are accepted, default html */
  lang?: string
  /** Optional one-line context the model wrote just before the fence */
  context?: string
  startIndex: number
  endIndex: number
  /** True if the closing ``` hasn't streamed in yet (live preview) */
  partial: boolean
}

// Match BOTH complete ```html ... ``` blocks AND a still-open ```html ... stream
// (so the preview can render in real-time as the model types).
const HTML_BLOCK_OPEN = /```(html|htm)\b([^\n]*)\n?/i
const HTML_BLOCK_FULL = /```(html|htm)\b([^\n]*)\n([\s\S]*?)```/g
const HTML_BLOCK_PARTIAL = /```(html|htm)\b([^\n]*)\n([\s\S]*)$/i

export function parseHtmlBlocks(text: string): ParsedHtmlBlock[] {
  const out: ParsedHtmlBlock[] = []
  // First pass: collect all complete blocks
  const taken = new Set<number>()
  let m: RegExpExecArray | null
  HTML_BLOCK_FULL.lastIndex = 0
  while ((m = HTML_BLOCK_FULL.exec(text)) !== null) {
    const lang = m[1]
    const contextLine = m[2]?.trim() || undefined
    const html = m[3]
    out.push({
      html,
      lang,
      context: contextLine,
      startIndex: m.index,
      endIndex: m.index + m[0].length,
      partial: false,
    })
    // Mark the matched range as taken
    for (let i = m.index; i < m.index + m[0].length; i++) taken.add(i)
  }
  // Second pass: if a ```html opener is present without a closing fence, add
  // it as a partial block so the preview can update as the model streams.
  const partialMatch = HTML_BLOCK_PARTIAL.exec(text)
  if (partialMatch) {
    const idx = partialMatch.index
    let overlaps = false
    for (const takenIdx of taken) {
      if (Math.abs(takenIdx - idx) < 10) {
        overlaps = true
        break
      }
    }
    if (!overlaps) {
      out.push({
        html: partialMatch[3] || '',
        lang: partialMatch[1],
        context: partialMatch[2]?.trim() || undefined,
        startIndex: idx,
        endIndex: text.length,
        partial: true,
      })
    }
  }
  // Sort by start position so the UI renders them in document order
  out.sort((a, b) => a.startIndex - b.startIndex)
  return out
}

/** Strip ```html ... ``` blocks from a chat message for display. */
export function stripHtmlBlocks(text: string): string {
  return text
    .replace(HTML_BLOCK_FULL, '')
    .replace(HTML_BLOCK_OPEN, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim()
}

/** Quick check — does the text contain anything that looks like an HTML block? */
export function hasHtmlBlock(text: string): boolean {
  return /```(html|htm)\b/i.test(text)
}
